#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int ans[501];
        for (int i = 1; i + 1 < N; i += 2) {
            ans[i] = i + 1;
            ans[i + 1] = i;
        }
        if (N % 2 == 1) ans[N] = N;
        for (int i = 1; i <= N; ++i) {
            if (i > 1) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
    }
    return 0;
}

